function refreshLayoutCards(config){const container=config.container,cards=visibleLayoutItems(container,config.selector),isGrid=getComputedStyle(container).display==="grid";config.handles?.forEach(({card,handle})=>{const index=cards.indexOf(card);handle.hidden=index<0||(isGrid&&index>=cards.length-1)});cards.forEach(refreshCardResponsiveState)}
function applyGridLayout(config,sizes,persist=true){const container=config.container,cards=visibleLayoutItems(container,config.selector);if(cards.length<1)return;const isGrid=getComputedStyle(container).display==="grid";if(cards.length<2||!isGrid){container.style.gridTemplateColumns="";const prefs=readLayoutPrefs();cards.forEach((card,index)=>{const saved=Number(prefs[freeWidthKey(config,card,index)]||0);if(saved>0)applyFreeCardWidth(config,card,index,saved,false);else refreshCardResponsiveState(card)});config.handles?.forEach(({handle})=>handle.hidden=false);return}cards.forEach(card=>{card.classList.remove("free-sized-card");card.style.width="";card.style.alignSelf="";card.style.height=""});const gap=layoutGap(container),available=layoutTrackWidth(container)-gap*(cards.length-1),fallbackMin=config.minSizes[config.minSizes.length-1]||160,mins=Array.from({length:cards.length},(_,i)=>config.minSizes[i]||fallbackMin),fitted=normalizeLayoutSizes(sizes.slice(0,cards.length),mins,available,config.growIndex);container.style.gridTemplateColumns=fitted.map(value=>`${Math.round(value)}px`).join(" ");config.sizes=fitted;if(persist)writeLayoutPref(config.storageKey,fitted.map(value=>Math.round(value)));requestAnimationFrame(()=>refreshLayoutCards(config))}
function setupGridResizers(container,selector,storageKey,minSizes,growIndex){if(!container||container.dataset.cardResizeReady==="true")return;const config={container,selector,storageKey,minSizes,growIndex,handles:[],sizes:[]};container.dataset.cardResizeReady="true";container.classList.add("resizable-ready");layoutResizeGroups.push(config);visibleLayoutItems(container,selector).forEach((card,cardIndex)=>{const handle=edgeHandle(card,"right","拖动外边框调整卡片宽度");handle.ariaOrientation="vertical";config.handles.push({card,handle});handle.addEventListener("pointerdown",event=>{if(event.button&&event.button!==0)return;const cards=visibleLayoutItems(container,selector),index=cards.indexOf(card),isGrid=getComputedStyle(container).display==="grid";if(index<0||(isGrid&&index>=cards.length-1))return;event.preventDefault();event.stopPropagation();const startX=event.clientX,startWidth=card.getBoundingClientRect().width,startSizes=currentGridSizes(config);handle.classList.add("is-dragging");card.classList.add("is-edge-resizing");container.classList.add("is-resizing");document.body.classList.add("is-card-resizing-x");const onMove=moveEvent=>{const delta=moveEvent.clientX-startX;if(isGrid)moveGridBoundary(config,index,startSizes,delta,true);else applyFreeCardWidth(config,card,index,startWidth+delta,true)};const onUp=()=>{window.removeEventListener("pointermove",onMove);window.removeEventListener("pointerup",onUp);handle.classList.remove("is-dragging");card.classList.remove("is-edge-resizing");container.classList.remove("is-resizing");document.body.classList.remove("is-card-resizing-x");pulseLayoutCards(config)};window.addEventListener("pointermove",onMove);window.addEventListener("pointerup",onUp,{once:true})});handle.addEventListener("keydown",event=>{if(!["ArrowLeft","ArrowRight"].includes(event.key))return;const cards=visibleLayoutItems(container,selector),index=cards.indexOf(card),isGrid=getComputedStyle(container).display==="grid";if(index<0||(isGrid&&index>=cards.length-1))return;event.preventDefault();const delta=event.key==="ArrowRight"?24:-24;if(isGrid)moveGridBoundary(config,index,currentGridSizes(config),delta,true);else applyFreeCardWidth(config,card,index,card.getBoundingClientRect().width+delta,true);pulseLayoutCards(config)})});const prefs=readLayoutPrefs()[storageKey],cards=visibleLayoutItems(container,selector);applyGridLayout(config,Array.isArray(prefs)&&prefs.length===cards.length?prefs:currentGridSizes(config),false)}
function setupOpsHeightResizer(){const footer=document.querySelector(".platform-ops");if(!footer||document.body.dataset.rowResizeReady==="true")return;document.body.dataset.rowResizeReady="true";const saved=Number(readLayoutPrefs().opsHeight||0);if(saved>0)document.documentElement.style.setProperty("--ops-h",`${saved}px`);const attach=(card,edge,mode,index)=>{const handle=edgeHandle(card,edge,"拖动外边框调整卡片高度");handle.ariaOrientation="horizontal";const savedCardH=Number(readLayoutPrefs()[freeHeightKey(card,index)]||0);if(savedCardH>0&&getComputedStyle(card.parentElement).display!=="grid")applyFreeCardHeight(card,index,savedCardH,false);handle.addEventListener("pointerdown",event=>{if(event.button&&event.button!==0)return;event.preventDefault();event.stopPropagation();const parent=card.parentElement,isGrid=getComputedStyle(parent).display==="grid",startY=event.clientY,startFooterH=footer.getBoundingClientRect().height,startCardH=card.getBoundingClientRect().height;handle.classList.add("is-dragging");card.classList.add("is-edge-resizing");document.body.classList.add("is-card-resizing-y");const onMove=moveEvent=>{const delta=moveEvent.clientY-startY;if(isGrid&&mode==="workspace")setOpsHeight(startFooterH-delta,true);else if(isGrid&&mode==="ops")setOpsHeight(startFooterH-delta,true);else applyFreeCardHeight(card,index,startCardH+(edge==="top"?-delta:delta),true)};const onUp=()=>{window.removeEventListener("pointermove",onMove);window.removeEventListener("pointerup",onUp);handle.classList.remove("is-dragging");card.classList.remove("is-edge-resizing");document.body.classList.remove("is-card-resizing-y");document.querySelectorAll(".panel-column,.ops-card").forEach(node=>{node.classList.remove("layout-resized");void node.offsetWidth;node.classList.add("layout-resized")})};window.addEventListener("pointermove",onMove);window.addEventListener("pointerup",onUp,{once:true})});handle.addEventListener("keydown",event=>{if(!["ArrowUp","ArrowDown"].includes(event.key))return;event.preventDefault();const parent=card.parentElement,isGrid=getComputedStyle(parent).display==="grid",delta=event.key==="ArrowDown"?32:-32;if(isGrid)setOpsHeight(footer.getBoundingClientRect().height-delta,true);else applyFreeCardHeight(card,index,card.getBoundingClientRect().height+(edge==="top"?-delta:delta),true)})};document.querySelectorAll(".main-layout .panel-column").forEach((card,index)=>attach(card,"bottom","workspace",index));document.querySelectorAll(".ops-grid .ops-card").forEach((card,index)=>{attach(card,"top","ops",index);attach(card,"bottom","free",index)})}
function initCardResizers(){setupGridResizers(document.querySelector(".main-layout"),".panel-column","mainColumns",[180,330,240],1);setupGridResizers(document.querySelector(".ops-grid"),".ops-card","opsColumns",[180,200,200,200,180],"all");setupOpsHeightResizer()}
function refreshCardResizers(){layoutResizeGroups.forEach(group=>applyGridLayout(group,group.sizes?.length?group.sizes:currentGridSizes(group),false))}
async function api(url,opt={}){const{supressAuthOverlay,suppressAuthOverlay=false,headers={},body,method="GET",...rest}=opt;const h={...headers};if(!(body instanceof FormData)&&!h["Content-Type"])h["Content-Type"]="application/json";if(method!=="GET"&&state.csrfToken)h["X-CSRF-Token"]=state.csrfToken;const res=await fetch(url,{credentials:"same-origin",headers:h,body,method,...rest});let payload=null;try{payload=await res.json()}catch{}if(!res.ok){if(res.status===401&&!suppressAuthOverlay&&!supressAuthOverlay)showAuthOverlay("登录已失效，请重新登录。");throw new Error(payload?.detail||payload?.message||"请求失败")}if(payload?.csrf_token)state.csrfToken=payload.csrf_token;if(payload?.security)state.security=payload.security;return payload}
function renderContent(content,style="chat"){const text=String(content||"").trim();if(!text)return"<p></p>";if(style==="code"){const lines=text.split("\n");const parts=[];let code=[],txt=[];const flushTxt=()=>{if(!txt.length)return;parts.push(`<p>${txt.map(l=>esc(l.trim())).join("<br>")}</p>`);txt=[]};const flushCode=()=>{if(!code.length)return;parts.push(`<pre class="message-code-block"><code>${esc(code.join("\n"))}</code></pre>`);code=[]};for(const raw of lines){const line=raw.replace(/\s+$/,"");if(!line.trim()){flushCode();flushTxt();continue}if(codeLine(line.trim())){flushTxt();code.push(line)}else{flushCode();txt.push(line)}}flushCode();flushTxt();return parts.join("")||`<p>${esc(text)}</p>`}return text.split(/\n{2,}/).map(seg=>seg.trim()).filter(Boolean).map(seg=>{const lines=seg.split("\n").map(l=>l.trim()).filter(Boolean);if(lines.every(l=>/^\d+\.\s+/.test(l)))return`<ol>${lines.map(l=>`<li>${esc(l.replace(/^\d+\.\s+/,""))}</li>`).join("")}</ol>`;if(lines.every(l=>/^-\s+/.test(l)))return`<ul>${lines.map(l=>`<li>${esc(l.replace(/^-\s+/,""))}</li>`).join("")}</ul>`;return`<p>${lines.map(esc).join("<br>")}</p>`}).join("")}
function bubble(role,content,meta="",media=[],style="chat",usage=null,citations=[]){const node=document.createElement("div");node.className=`message ${role} ${style==="code"?"code-style":"chat-style"}`;const mediaHtml=media.length?`<div class="message-media-grid">${media.map(item=>`<a class="message-media-card" href="${esc(item.url)}" target="_blank" rel="noreferrer"><img src="${esc(item.url)}" alt="${esc(item.path||"图片")}" loading="lazy"><span>${esc(item.path||"图片预览")}</span></a>`).join("")}</div>`:"";const citationHtml=citations.length?`<div class="message-citations">${citations.map((item,index)=>`<div class="message-citation-card"><strong>来源 ${index+1} · ${esc(item.title||item.filename||item.document_id||"未命名文档")}</strong><div class="message-citation-meta">召回：${esc((item.retrieval||[]).join(" + ")||"vector")} · 分数 ${esc(Number(item.score||0).toFixed(3))}${item.filename?`<br>${esc(item.filename)}`:""}</div></div>`).join("")}</div>`:"";const usageText=fmtUsageSummary(usage);const usageHtml=usageText?`<div class="message-usage">${esc(usageText)}</div>`:"";node.innerHTML=`<span class="meta">${esc(meta)}</span><div class="message-content">${renderContent(content,style)}</div>${citationHtml}${mediaHtml}${usageHtml}`;return node}
function appendMessage(role,content,meta,media=[],style="chat",usage=null,citations=[]){els.chatLog.appendChild(bubble(role,content,meta,media,style,usage,citations));els.chatLog.scrollTop=els.chatLog.scrollHeight}
function renderList(container,items,render,empty="暂无数据"){container.innerHTML="";if(!items.length){container.innerHTML=`<div class="status-item status-item-empty"><p>${esc(empty)}</p></div>`;return}for(const item of items){const n=document.createElement("div");n.className="status-item";n.innerHTML=render(item);container.appendChild(n)}}
function renderChannelOptions(){const opts=state.channels.length?state.channels:["qq","weixin"];const preferred=state.targetChannelSelection||els.targetChannel.value||"weixin";els.targetChannel.innerHTML=opts.map(v=>`<option value="${esc(v)}">${esc(chLabel(v))}</option>`).join("");const selected=opts.includes(preferred)?preferred:(opts.includes("weixin")?"weixin":opts[0]||"");if(selected){els.targetChannel.value=selected;state.targetChannelSelection=selected}}
function renderChannelSyncState(){els.channelSyncStatus.textContent=state.channelSyncEnabled?"当前启用":"当前停用";els.channelSyncStatus.classList.toggle("pending-tag",state.channelSyncEnabled);els.channelSyncToggleBtn.textContent=state.channelSyncEnabled?"终止":"启用";els.channelSyncToggleBtn.classList.toggle("assistant-toggle-start",!state.channelSyncEnabled);els.channelSyncToggleBtn.classList.toggle("assistant-toggle-stop",state.channelSyncEnabled)}
