function renderSecurityBanner(){const devMode=Boolean(state.security?.dev_mode);toggleHidden(els.devBanner,!devMode);if(devMode)els.devBanner.innerHTML="<strong>开发模式</strong><span>当前控制台运行在非生产模式，Cookie Secure 与部分安全约束已为本机调试放宽。</span>";const fileMb=state.security?.upload_max_file_mb||10,totalMb=state.security?.upload_max_total_mb||30;els.knowledgeLimitsTag.textContent=`单文件 ${fileMb} MB · 总计 ${totalMb} MB`}
function renderRagStatus(){const s=state.ragStatus;if(!s){els.ragStatus.innerHTML=`<div class="status-item status-item-empty"><p>正在读取 Milvus RAG 状态...</p></div>`;return}const libs=(s.libraries||[]).map(i=>`${esc(i.name)} ${i.available?"已就绪":"缺失"}`).join(" · ");els.ragStatus.innerHTML=`<div class="status-item"><strong>${esc(String(s.backend||"rag").toUpperCase())} · ${s.connected?"已连接":"未连接"}</strong><p>Collection：${esc(s.collection_name||"-")}<br>Embedding：${esc(s.embedding_model||"-")} · 维度 ${esc(s.vector_dimension||0)}<br>文档 ${esc(s.knowledge_docs||0)} · Chunk ${esc(s.knowledge_chunks||0)} · BM25 ${s.bm25_available?"可用":"回退分词"}</p><p>${esc(libs||"")}</p>${s.last_error?`<p class="danger-text">${esc(s.last_error)}</p>`:""}</div>`}
function renderMcpDiagnostics(){const p=state.mcpDiagnostics;if(!p){els.mcpDiagnostics.innerHTML=`<div class="trace-empty">可以先填入 MCP 模板，再执行校验或探测。</div>`;return}const items=p.servers||[];if(!items.length){els.mcpDiagnostics.innerHTML=`<div class="trace-empty">当前没有 MCP server 配置。</div>`;return}els.mcpDiagnostics.innerHTML=items.map(item=>`<div class="trace-block"><div class="ops-line"><strong>${esc(item.name)}</strong><span class="status-pill ${item.valid&&(!("reachable" in item)||item.reachable)?"enabled":"disabled"}">${item.valid?(("reachable" in item)?(item.reachable?"可达":"不可达"):"已校验"):"无效配置"}</span></div><p>Transport：${esc(item.transport||"-")} · Timeout：${esc(item.tool_timeout||0)}s</p><p>${esc(item.endpoint||"-")}${item.arguments?`<br>${esc(item.arguments)}`:""}</p>${item.issues?.length?`<p class="danger-text">${esc(item.issues.join("；"))}</p>`:""}${item.warnings?.length?`<p>${esc(item.warnings.join("；"))}</p>`:""}${item.probe_detail?`<p>探测结果：${esc(item.probe_detail)}</p>`:""}</div>`).join("")}
function renderUploads(){els.uploadList.innerHTML="";const groups=[];if(state.deferredUploads.length)groups.push({title:"已暂存附件，等待文字指令",items:state.deferredUploads,deferred:true});if(state.pendingUploads.length)groups.push({title:"本轮待发送附件",items:state.pendingUploads,deferred:false});els.uploadList.classList.toggle("has-items",groups.length>0);for(const g of groups){const block=document.createElement("div");block.className="upload-group";block.innerHTML=`<div class="upload-group-title">${g.title}</div><div class="upload-group-list"></div>`;const list=block.querySelector(".upload-group-list");for(const file of g.items){const chip=document.createElement("div");chip.className=`upload-chip ${g.deferred?"upload-chip-deferred":""}`;chip.innerHTML=g.deferred?`<span class="upload-chip-name">${esc(file.name)}</span><span class="upload-chip-state">待命中</span>`:`<span class="upload-chip-name">${esc(file.name)}</span><button type="button" class="upload-chip-remove" data-remove-upload="${esc(file.path)}">移除</button>`;list.appendChild(chip)}els.uploadList.appendChild(block)}renderDeferredStatus()}
