function renderAssistants(){els.assistantList.innerHTML="";const assistants=[...state.assistants].sort((a,b)=>{const ap=String(a.id||"").toLowerCase()==="consult"?0:1,bp=String(b.id||"").toLowerCase()==="consult"?0:1;return ap-bp});assistants.forEach((a,index)=>{const active=a.id===state.selectedAssistantId,started=a.id===state.startedAssistantId;const node=document.createElement("article");node.className=`assistant-card${active?" active":""}`;node.dataset.assistantId=a.id;node.innerHTML=`<div class="assistant-row-main"><div class="assistant-card-title"><div class="assistant-row-top"><span class="assistant-row-index">${esc(String(index+1).padStart(2,"0"))}</span><strong>${esc(a.name)}</strong></div><div class="assistant-row-meta"><span class="status-pill">${esc(a.id)}</span><span class="status-pill ${a.enabled?"enabled":"disabled"}">${a.enabled?"READY":"DISABLED"}</span></div></div></div><button type="button" class="assistant-toggle ${started?"assistant-toggle-stop":"assistant-toggle-start"}" data-start-assistant="${esc(a.id)}">${started?"终止":"启用"}</button>`;els.assistantList.appendChild(node)})}
function renderAssistantVersions(){renderList(els.assistantVersionList,state.assistantVersions,i=>`<div class="ops-line"><strong>v${esc(i.version)}</strong><span>${esc(fmtTime(i.changed_at))}</span></div><p>变更人：${esc(i.changed_by||"-")} · 模型：${esc(i.provider||"-")}/${esc(i.model||"-")}</p><p>${esc(i.change_note||"未填写变更说明")}</p>`,"选择助手后可查看 Prompt 版本历史。")}
function renderAssistantSourceFiles(files){const box=$("assistantSourceFiles");if(!box)return;const labels={config:"主配置",workspace:"助手工作区",agent_prompt:"系统 Prompt",identity:"身份文件",tools:"工具文件",versions:"版本历史"};const entries=Object.entries(files||{}).filter(([,value])=>String(value||"").trim());if(!entries.length){box.innerHTML='<div class="trace-empty">保存后会同步到后端配置文件和助手工作区文件。</div>';return}box.innerHTML=entries.map(([key,value])=>`<div class="backend-file-item"><strong>${esc(labels[key]||key)}</strong><code>${esc(value)}</code></div>`).join("")}
