function renderTaskSchedulePreview(){const scheduleKind=els.taskScheduleKind.value;const scheduleText=scheduleKind==="interval"?`每 ${els.taskIntervalMinutes.value||0} 分钟执行一次`:scheduleKind==="cron"?`Cron：${els.taskCronExpression.value.trim()||"尚未填写"}`:"仅手动执行";const conditions=[];if(els.taskRequireRag.checked)conditions.push("要求 RAG 已连接");if(els.taskRequireChannel.checked)conditions.push("要求目标渠道在线");const gap=Number(els.taskMinSuccessGap.value||0);if(gap>0)conditions.push(`距离上次成功至少 ${gap} 分钟`);els.taskSchedulePreview.innerHTML=`<div class="trace-block"><h4>任务调度预览</h4><p>${esc(scheduleText)} · ${esc(taskCollaborationLabel(els.taskCollaborationMode.value))}</p><p>${esc(conditions.join(" · ")||"无额外执行条件")}</p></div>`}
function renderTaskConditionItems(evaluation){const items=evaluation?.items||[];if(!items.length)return`<p class="task-condition-empty">当前没有额外执行条件。</p>`;return`<div class="task-condition-list">${items.map(item=>`<div class="task-condition-item ${item.matched?"matched":"blocked"}"><strong>${esc(item.label||"-")}</strong><span class="status-pill ${item.matched?"enabled":"disabled"}">${item.matched?"已命中":"未命中"}</span><p>${esc(item.detail||"-")}</p></div>`).join("")}</div>`}
function renderTaskBlockingSummary(task){const lastStatus=String(task?.last_status||"").toLowerCase();const lastResult=String(task?.last_result||"").trim();if(lastStatus==="skipped"&&lastResult)return`<div class="task-block-summary"><div class="ops-line"><strong>最近一次阻塞原因</strong><span>${esc(fmtTime(task?.last_run_at))}</span></div><p class="danger-text">${esc(lastResult)}</p></div>`;const blockingReason=String(task?.condition_evaluation?.blocking_reason||"").trim();if(!blockingReason)return"";return`<div class="task-block-summary"><div class="ops-line"><strong>当前阻塞判断</strong><span>${esc(fmtTime(task?.updated_at))}</span></div><p class="danger-text">${esc(blockingReason)}</p></div>`}
function renderTaskConditionSummary(task){const evaluation=task.condition_evaluation||null;if(!evaluation)return`<p>当前条件状态暂不可用。</p>`;return`<div class="task-condition-summary"><div class="ops-line"><strong>${esc(evaluation.summary||"条件判定")}</strong><span class="status-pill ${evaluation.ready?"enabled":"disabled"}">${evaluation.ready?"可执行":"已阻塞"}</span></div>${evaluation.blocking_reason?`<p class="danger-text">${esc(evaluation.blocking_reason)}</p>`:""}${renderTaskConditionItems(evaluation)}</div>`}
function populateForm(a){state.mcpDiagnostics=null;renderMcpDiagnostics();if(!a){form.root.reset();form.id.value="";form.mcp.value="";form.promptVersion.value=1;form.promptChangeNote.value="";form.dailyTokenLimit.value="";state.assistantVersions=[];renderAssistantVersions();renderAssistantSourceFiles(null);els.configMode.textContent="新增模式";return}form.id.value=a.id||"";form.name.value=a.name||"";form.description.value=a.description||"";form.persona.value=a.persona_prompt||"";form.promptVersion.value=a.prompt_version||1;form.promptChangeNote.value=a.prompt_change_note||"";form.dailyTokenLimit.value=a.daily_token_limit??"";form.model.value=a.model||"";form.provider.value=a.provider||"";form.imageModel.value=a.image_model||"";form.imageProvider.value=a.image_provider||"";form.tools.value=(a.tool_names||[]).join(", ");form.skills.value=(a.enabled_skills||[]).join(", ");form.disabledSkills.value=(a.disabled_skills||[]).join(", ");form.aliases.value=(a.routing?.aliases||[]).join(", ");form.keywords.value=(a.routing?.keywords||[]).join(", ");form.mcp.value=fmtJson(a.mcp_servers);form.temperature.value=a.temperature??"";form.maxTokens.value=a.max_tokens??"";form.maxIterations.value=a.max_tool_iterations??"";form.contextWindow.value=a.context_window_tokens??"";form.resultChars.value=a.max_tool_result_chars??"";form.reasoningEffort.value=a.reasoning_effort||"";form.enabled.checked=a.enabled!==false;renderAssistantSourceFiles(a.source_files);els.configMode.textContent="编辑模式"}
function selectAssistant(id){const a=state.assistants.find(v=>v.id===id)||null;if(!a){state.selectedAssistantId=null;els.assistantBadge.textContent="未选择助手";populateForm(null);renderAssistants();return}state.selectedAssistantId=a.id;els.assistantBadge.textContent=`${a.name} · ${a.id}`;populateForm(a);loadAssistantVersions(a.id).catch(()=>{});renderAssistants();updateConfigPanel()}
