function setMcpTemplate(payload){form.mcp.value=JSON.stringify(payload,null,2);state.mcpDiagnostics=null;renderMcpDiagnostics()}
function currentMcpPayload(){if(!form.mcp.value.trim())return{};try{return JSON.parse(form.mcp.value)}catch{throw new Error("MCP 配置 JSON 格式不正确")}}
async function runMcpCheck(mode){const payload=currentMcpPayload();const path=mode==="probe"?"/api/mcp/probe":"/api/mcp/validate";state.mcpDiagnostics={servers:[{name:"loading",valid:true,issues:[],warnings:[],probe_detail:mode==="probe"?"正在探测 MCP...":"正在校验 MCP..."}]};renderMcpDiagnostics();state.mcpDiagnostics=await api(path,{method:"POST",body:JSON.stringify({mcp_servers:payload})});renderMcpDiagnostics()}
function assistantPayload(){let mcp={};if(form.mcp.value.trim())try{mcp=JSON.parse(form.mcp.value)}catch{throw new Error("MCP 配置 JSON 格式不正确")}return{id:form.id.value.trim(),name:form.name.value.trim(),description:form.description.value.trim(),persona_prompt:form.persona.value.trim(),prompt_version:form.promptVersion.value?Number(form.promptVersion.value):1,prompt_change_note:form.promptChangeNote.value.trim(),daily_token_limit:form.dailyTokenLimit.value?Number(form.dailyTokenLimit.value):null,model:form.model.value.trim(),provider:form.provider.value.trim()||"auto",image_model:form.imageModel.value.trim()||null,image_provider:form.imageProvider.value.trim()||null,tool_names:csv(form.tools.value),enabled_skills:csv(form.skills.value),disabled_skills:csv(form.disabledSkills.value),routing:{aliases:csv(form.aliases.value),keywords:csv(form.keywords.value)},mcp_servers:mcp,temperature:form.temperature.value?Number(form.temperature.value):null,max_tokens:form.maxTokens.value?Number(form.maxTokens.value):null,max_tool_iterations:form.maxIterations.value?Number(form.maxIterations.value):null,context_window_tokens:form.contextWindow.value?Number(form.contextWindow.value):null,max_tool_result_chars:form.resultChars.value?Number(form.resultChars.value):null,reasoning_effort:form.reasoningEffort.value.trim()||null,enabled:form.enabled.checked}}
function applyRoleGuards(){const writable=can("admin"),canChat=can("viewer");const userText=state.currentUser?`${state.currentUser.username} · ${state.currentUser.role}`:"未登录";els.currentUser.textContent=userText;if(els.heroCurrentUser)els.heroCurrentUser.textContent=userText;els.authRoleBadge.textContent=state.currentUser?`权限 ${state.currentUser.role}`:"访客";toggleHidden(els.newAssistantBtn,!writable);toggleHidden(els.deleteAssistantBtn,!writable);toggleHidden(els.userForm,!writable);toggleHidden(els.userList,!writable);for(const c of form.root.querySelectorAll("input,textarea,select,button")){if(c.id==="resetAssistantBtn"){c.disabled=false;continue}c.disabled=!writable}for(const c of els.knowledgeUploadForm.querySelectorAll("input,button"))c.disabled=!writable;for(const c of els.taskForm.querySelectorAll("input,textarea,select,button"))c.disabled=!writable;for(const c of els.chatForm.querySelectorAll("textarea,input,select,button"))c.disabled=!canChat;if(els.fileInput)els.fileInput.disabled=!writable;if(els.voiceBtn)els.voiceBtn.disabled=!canChat||!state.recognition;if(els.targetChannel)els.targetChannel.disabled=!writable;if(els.channelSyncToggleBtn)els.channelSyncToggleBtn.disabled=!writable;if(writable)for(const c of els.userForm.querySelectorAll("input,select,button"))c.disabled=false}
function updateDashboard(overview){const d=overview?.dashboard||state.dashboard||{traces_total:0,traces_failed:0,avg_duration_ms:0,tasks_total:0,tasks_enabled:0,knowledge_docs:0,knowledge_chunks:0,trace_total_tokens:0};state.dashboard=d;els.dashboardBadge.textContent=`Trace ${d.traces_total} · 失败 ${d.traces_failed||0} · 平均 ${fmtNum(d.avg_duration_ms||0)} ms · 任务 ${d.tasks_enabled||0}/${d.tasks_total||0} · 知识 ${d.knowledge_docs||0} / Chunk ${d.knowledge_chunks||0} · Tokens ${fmtNum(d.trace_total_tokens||0)}`}
async function loadOverview(){const o=await api("/api/overview");state.currentUser=o.user||state.currentUser;state.assistants=o.assistants||[];state.channels=Object.keys(o.channels||{});state.security=o.security||state.security;state.startedAssistantId=o.started_assistant_id||o.default_assistant_id||"consult";els.defaultAssistant.textContent=o.default_assistant_id||"-";if(els.heroDefaultAssistant)els.heroDefaultAssistant.textContent=o.default_assistant_id||"-";els.sessionId.textContent=state.sessionId;if(els.heroSessionId)els.heroSessionId.textContent=state.sessionId;els.channelBadge.textContent="Web 会话";renderAssistants();renderChannelOptions();renderChannelSyncState();renderSecurityBanner();updateDashboard(o);applyRoleGuards();renderList(els.channelStatus,Object.entries(o.channels||{}).map(([name,value])=>({name,...value})),i=>`<strong>${esc(chLabel(i.name))}</strong><p>启用：${i.enabled?"是":"否"}<br>运行中：${i.running?"是":"否"}</p>`);renderList(els.skillsCatalog,o.skills||[],i=>`<strong>${esc(i.name)}</strong><p>${esc(i.source)} · ${esc(i.path)}</p>`);renderList(els.mcpCatalog,o.mcp_servers||[],i=>{const parts=[i.transport||"unknown"];if(i.endpoint)parts.push(i.endpoint);return`<div class="ops-line"><strong>${esc(i.name)}</strong><span class="status-pill ${i.valid?"enabled":"disabled"}">${i.valid?"就绪":"配置异常"}</span></div><p>${esc(parts.join(" · "))}${i.arguments?`<br>${esc(i.arguments)}`:""}</p><p>来源助手：${esc((i.sources||[]).join("、")||"全局")} · 工具白名单：${esc((i.enabled_tools||[]).join(", ")||"(none)")}</p>${i.issues?.length?`<p class="danger-text">${esc(i.issues.join("；"))}</p>`:""}${i.warnings?.length?`<p>${esc(i.warnings.join("；"))}</p>`:""}`},"当前还没有为 bot 配置 MCP 服务");const preferred=state.selectedAssistantId&&state.assistants.some(v=>v.id===state.selectedAssistantId)?state.selectedAssistantId:(o.started_assistant_id||o.default_assistant_id||state.assistants[0]?.id||null);selectAssistant(preferred)}
function renderKnowledgeDocuments(){renderList(els.knowledgeList,state.knowledgeDocuments,i=>`<div class="ops-line"><strong>${esc(i.title)}</strong><span class="mini-actions"><button type="button" class="mini-action" data-open-knowledge="${esc(i.id)}">预览</button>${can("admin")?`<button type="button" class="mini-action" data-delete-knowledge="${esc(i.id)}">删除</button>`:""}</span></div><p>范围：${esc((i.assistant_scope||[]).join("、")||"全部助手")}</p><p>分块：${esc(i.chunk_count)} · 创建人：${esc(i.created_by)}</p><p>${esc(i.filename)}</p>`,"还没有知识文档，先上传 txt / md / pdf / docx 文件。")}
function renderKnowledgeSearchResults(){renderList(els.knowledgeSearchResults,state.knowledgeSearchResults,i=>`<strong>${esc(i.title)} · 融合分 ${esc(Number(i.score||0).toFixed(3))}</strong><p>${esc(i.content)}</p><p>${esc(i.filename)}</p><p>召回：${esc((i.retrieval||[]).join(" + ")||"-")} · 向量 ${esc(Number(i.vector_score||0).toFixed(3))} · 关键词 ${esc(Number(i.lexical_score||0).toFixed(3))}</p>`,"输入问题后可查看检索结果。")}
function renderKnowledgeDetail(){const d=state.selectedKnowledgeDetail;if(!d){els.knowledgeDetail.innerHTML=`<div class="trace-empty">选择一份知识文档即可查看 chunk 预览与助手范围。</div>`;return}els.knowledgeDetail.innerHTML=`<div class="trace-card-head"><strong>${esc(d.title||"-")}</strong><span>${esc((d.assistant_scope||[]).join("、")||"全部助手")}</span></div><div class="trace-block"><h4>文档信息</h4><pre>${esc(`${d.filename||"-"}\n${d.content_type||"-"}\nChunk ${d.chunk_count||0} · 创建人 ${d.created_by||"-"}`)}</pre></div><div class="trace-block"><h4>Chunk 预览</h4><div class="trace-events">${(d.chunks||[]).map(c=>`<div class="trace-event"><div class="trace-event-meta"><strong>Chunk ${esc(c.chunk_index)}</strong><span>${esc((c.assistant_scope||[]).join("、")||"全部助手")}</span></div><pre>${esc(c.content||"-")}</pre></div>`).join("")||"<p>暂无 chunk 数据</p>"}</div></div>`}
async function loadRagStatus(){if(!can("viewer"))return;state.ragStatus=await api("/api/rag/status");renderRagStatus()}
