function renderTaskRuns(task){if(state.selectedTaskId!==task.id||!state.taskRuns.length)return"";return`<div class="mini-log">${state.taskRuns.map(run=>`<div class="mini-log-item"><strong>${esc(run.status)}</strong><span>${esc(fmtTime(run.completed_at||run.started_at))}</span><p>${esc(run.result||"-")}</p></div>`).join("")}</div>`}
function renderTasks(){renderList(els.taskList,state.tasks,i=>`<div class="ops-line"><div><strong>${esc(i.name)}</strong><p class="list-subtle">助手 ${esc(i.assistant_id)} · ${esc(i.task_kind||"generic")} · ${esc(i.schedule_kind==="interval"?`每 ${i.interval_minutes} 分钟`:i.schedule_kind==="cron"?`Cron ${i.cron_expression||"-"}`:"手动")}</p></div><span class="status-pill ${i.enabled?"enabled":"disabled"}">${i.enabled?"启用":"停用"}</span></div><p class="list-subtle">协同：${esc(taskCollaborationLabel(i.collaboration_mode))}</p><p class="list-subtle">条件：${i.require_rag_connected?"RAG 已连接 · ":""}${i.require_channel_online?"渠道在线 · ":""}最少间隔 ${esc(i.min_success_gap_minutes||0)} 分钟</p>${renderTaskBlockingSummary(i)}${renderTaskConditionSummary(i)}<div class="list-meta-row"><span>下次执行 ${esc(fmtTime(i.next_run_at))}</span><span>最近状态 ${esc(i.last_status||"idle")}</span><span>重试 ${esc(i.max_retries||0)} / ${esc(i.retry_backoff_seconds||60)}s</span></div><div class="mini-actions">${can("admin")?`<button type="button" class="mini-action" data-edit-task="${esc(i.id)}">编辑</button><button type="button" class="mini-action" data-run-task="${esc(i.id)}">立即运行</button>`:""}<button type="button" class="mini-action" data-runs-task="${esc(i.id)}">运行记录</button>${can("admin")?`<button type="button" class="mini-action danger-text" data-delete-task="${esc(i.id)}">删除</button>`:""}</div>${renderTaskRuns(i)}`,"当前还没有自动化任务。")}
async function loadTasks(){if(!can("viewer"))return;state.tasks=await api("/api/tasks");renderTasks()}
async function loadTaskRuns(taskId){state.selectedTaskId=taskId;state.taskRuns=await api(`/api/tasks/${encodeURIComponent(taskId)}/runs`);renderTasks()}
function populateTaskForm(task){els.taskId.value=task?.id||"";els.taskName.value=task?.name||"";els.taskAssistantId.value=task?.assistant_id||state.selectedAssistantId||"consult";els.taskPrompt.value=task?.prompt||"";els.taskKind.value=task?.task_kind||"generic";els.taskCollaborationMode.value=task?.collaboration_mode||"inherit";els.taskScheduleKind.value=task?.schedule_kind||"manual";els.taskCronExpression.value=task?.cron_expression||"";els.taskIntervalMinutes.value=task?.interval_minutes??60;els.taskRequireRag.checked=task?.require_rag_connected===true;els.taskRequireChannel.checked=task?.require_channel_online===true;els.taskMinSuccessGap.value=task?.min_success_gap_minutes??0;els.taskMaxRetries.value=task?.max_retries??0;els.taskRetryBackoff.value=task?.retry_backoff_seconds??60;els.taskTargetChannel.value=task?.target_channel||"";els.taskTargetChatId.value=task?.target_chat_id||"";els.taskEnabled.checked=task?.enabled!==false;renderTaskSchedulePreview()}
function resetTaskForm(){els.taskForm.reset();els.taskId.value="";els.taskKind.value="generic";els.taskCollaborationMode.value="inherit";els.taskCronExpression.value="";els.taskIntervalMinutes.value=60;els.taskRequireRag.checked=false;els.taskRequireChannel.checked=false;els.taskMinSuccessGap.value=0;els.taskMaxRetries.value=0;els.taskRetryBackoff.value=60;els.taskEnabled.checked=true;els.taskAssistantId.value=state.selectedAssistantId||"consult";renderTaskSchedulePreview()}
function renderCollaborationTrace(events){const start=events.find(e=>e.event_type==="collaboration_start"),plan=events.find(e=>e.event_type==="collaboration_plan"),summary=events.find(e=>e.event_type==="collaboration_summary"),workers=events.filter(e=>e.event_type==="collaboration_worker_result");if(!start&&!plan&&!summary&&!workers.length)return"";const meta=start?.metadata||{};return`<div class="trace-block collaboration-trace"><h4>协同执行视图</h4><div class="collab-overview"><span>Planner：${esc(meta.planner_assistant_id||plan?.metadata?.planner_assistant_id||"-")}</span><span>Workers：${esc((meta.worker_assistant_ids||workers.map(e=>e.metadata?.assistant_id).filter(Boolean)).join("、")||"-")}</span><span>Summary：${esc(meta.synthesis_assistant_id||summary?.metadata?.synthesis_assistant_id||"-")}</span></div>${plan?`<section class="collab-phase"><div class="trace-event-meta"><strong>Planner</strong><span>${esc(fmtTime(plan.created_at))}</span></div><pre class="trace-scroll-limit">${esc(plan.content||"-")}</pre></section>`:""}${workers.length?`<section class="collab-phase"><div class="trace-event-meta"><strong>Workers</strong><span>${esc(workers.length)} 个执行结果</span></div><div class="collab-workers">${workers.map(e=>`<article class="collab-worker"><div class="trace-event-meta"><strong>${esc(e.metadata?.assistant_name||e.metadata?.assistant_id||"Worker")}</strong><span>${esc(fmtTime(e.created_at))}</span></div><pre class="trace-scroll-limit">${esc(e.content||"-")}</pre></article>`).join("")}</div></section>`:""}${summary?`<section class="collab-phase"><div class="trace-event-meta"><strong>Summary</strong><span>${esc(fmtTime(summary.created_at))}</span></div><pre class="trace-scroll-limit">${esc(summary.content||"-")}</pre></section>`:""}</div>`}
function renderTraceDetail(trace){if(!trace){els.traceDetail.innerHTML=`<div class="trace-empty">选择一条 Trace 查看工具调用和响应详情。</div>`;return}const usageText=fmtUsageSummary(trace),events=trace.events||[],knowledgeHits=events.filter(e=>e.event_type==="knowledge_hit"),collabEvents=events.filter(e=>String(e.event_type||"").startsWith("collaboration_")),otherEvents=events.filter(e=>e.event_type!=="knowledge_hit"&&!String(e.event_type||"").startsWith("collaboration_"));els.traceDetail.innerHTML=`<div class="trace-card-head"><strong>${esc(trace.assistant_id)} · ${esc(trace.status)}</strong><span>${esc(fmtTime(trace.started_at))}</span></div><div class="trace-block"><h4>执行概览</h4><p>渠道：${esc(chLabel(trace.channel))} · 耗时 ${esc(fmtNum(trace.duration_ms||0))} ms${usageText?`<br>${esc(usageText)}`:""}</p></div>${renderCollaborationTrace(collabEvents)}${knowledgeHits.length?`<div class="trace-block"><h4>RAG 证据</h4><div class="trace-evidence-list">${knowledgeHits.map(e=>`<div class="trace-evidence-card"><div class="trace-event-meta"><strong>${esc(e.metadata?.title||e.metadata?.filename||"未命名文档")}</strong><span>${esc(fmtTime(e.created_at))}</span></div><p class="trace-evidence-meta">阶段：${esc(e.metadata?.phase||"chat")} · 助手：${esc(e.metadata?.assistant_id||trace.assistant_id)} · 召回：${esc((e.metadata?.retrieval||[]).join(" + ")||"-")} · 分数 ${esc(Number(e.metadata?.score||0).toFixed(3))}${e.metadata?.filename?` · ${esc(e.metadata.filename)}`:""}</p><pre class="trace-scroll-limit">${esc(e.content||"-")}</pre></div>`).join("")}</div></div>`:""}<div class="trace-block"><h4>用户输入</h4><pre class="trace-scroll-limit">${esc(trace.request_content||"-")}</pre></div><div class="trace-block"><h4>助手输出</h4><pre class="trace-scroll-limit">${esc(trace.response_content||"-")}</pre></div><div class="trace-block"><h4>工具 / 事件流</h4><div class="trace-events trace-scroll-limit">${otherEvents.map(e=>`<div class="trace-event"><div class="trace-event-meta"><strong>${esc(e.event_type)}</strong><span>${esc(fmtTime(e.created_at))}</span></div><pre class="trace-scroll-limit">${esc(e.content||"-")}</pre></div>`).join("")||"<p>暂无事件</p>"}</div></div>`}
function renderTraces(){renderList(els.traceList,state.traces,i=>`<div class="ops-line"><div><strong>${esc(i.assistant_id)}</strong><p class="list-subtle">${esc(chLabel(i.channel))} · ${esc(fmtTime(i.started_at))} · ${esc(i.duration_ms)} ms</p></div><span class="status-pill ${i.status==="completed"?"enabled":"disabled"}">${esc(i.status)}</span></div><p class="list-preview">${esc(i.request_content||"-")}</p><div class="mini-actions"><button type="button" class="mini-action" data-open-trace="${esc(i.id)}">查看详情</button></div>`,"暂无 Trace 记录。")}
async function loadTraces(){if(!can("viewer"))return;state.traces=await api("/api/traces");renderTraces();if(!state.selectedTraceId&&state.traces.length)await loadTraceDetail(state.traces[0].id);else if(!state.traces.some(v=>v.id===state.selectedTraceId)){state.selectedTraceId=null;renderTraceDetail(null)}}
async function loadTraceDetail(traceId){state.selectedTraceId=traceId;renderTraceDetail(await api(`/api/traces/${encodeURIComponent(traceId)}`))}
function populateUserForm(user){els.userId.value=user?.id||"";els.userUsername.value=user?.username||"";els.userPassword.value="";els.userRole.value=user?.role||"viewer";els.userEnabled.checked=user?.enabled!==false}
function renderUsers(){renderList(els.userList,state.users,i=>`<div class="ops-line"><strong>${esc(i.username)}</strong><span class="status-pill ${i.enabled?"enabled":"disabled"}">${esc(i.role)}</span></div><p>最后登录：${esc(fmtTime(i.last_login_at))}</p><div class="mini-actions"><button type="button" class="mini-action" data-edit-user="${esc(i.id)}">编辑</button>${i.username!=="admin"?`<button type="button" class="mini-action danger-text" data-delete-user="${esc(i.id)}">删除</button>`:""}</div>`,"当前没有额外账号。")}
async function loadUsers(){if(!can("admin"))return;state.users=await api("/api/users");renderUsers()}
async function refreshPlatformData(){const jobs=[loadRagStatus(),loadKnowledgeDocuments(),loadTasks(),loadTraces()];if(can("admin"))jobs.push(loadUsers());await Promise.all(jobs)}
async function uploadFiles(files){if(!files.length)return;const data=new FormData();data.append("session_id",state.sessionId);for(const file of files)data.append("files",file);const payload=await api("/api/uploads",{method:"POST",body:data});state.pendingUploads.push(...(payload.files||[]));renderUploads()}
function initSpeechRecognition(){const R=window.SpeechRecognition||window.webkitSpeechRecognition;if(!R){els.voiceBtn.disabled=true;els.speechStatus.textContent="浏览器不支持";return}const rec=new R();rec.lang="zh-CN";rec.continuous=false;rec.interimResults=true;state.recognition=rec;rec.onstart=()=>{state.isRecognizing=true;state.speechBaseText=els.chatInput.value;els.speechStatus.textContent="语音识别中";els.speechStatus.classList.add("pending-tag");els.voiceBtn.textContent="停止识别"};rec.onresult=e=>{let text="";for(let i=e.resultIndex;i<e.results.length;i+=1)text+=e.results[i][0].transcript;els.chatInput.value=[state.speechBaseText.trim(),text.trim()].filter(Boolean).join("\n")};rec.onend=()=>{state.isRecognizing=false;els.speechStatus.textContent="语音待命";els.speechStatus.classList.remove("pending-tag");els.voiceBtn.textContent="语音识别"};rec.onerror=()=>appendMessage("assistant","语音识别失败，请检查浏览器权限后重试。","系统")}
function showAuthOverlay(msg=""){hideAuthLoading();els.loginError.textContent=msg;els.authOverlay.classList.remove("hidden")}
function toggleBootstrapMode(){toggleHidden(els.bootstrapPanel,!state.bootstrapRequired);toggleHidden(els.loginForm,state.bootstrapRequired)}
function hideAuthOverlay(){hideAuthLoading();els.loginError.textContent="";els.bootstrapError.textContent="";els.authOverlay.classList.add("hidden")}
async function refreshBootstrapStatus(){const status=await api("/api/auth/bootstrap-status",{suppressAuthOverlay:true});state.bootstrapRequired=Boolean(status.bootstrap_required);state.security={...(state.security||{}),dev_mode:Boolean(status.dev_mode),auth_enabled:Boolean(status.auth_enabled)};toggleBootstrapMode();renderSecurityBanner();return status}
async function bootstrapSession(loadingText="正在检查登录状态...",minDurationMs=450){return withLoadingGate(loadingText,async()=>{try{await refreshBootstrapStatus();const p=await api("/api/auth/me",{suppressAuthOverlay:true});state.currentUser=p.user;state.csrfToken=p.csrf_token||state.csrfToken;state.security=p.security||state.security;await loadOverview();await refreshPlatformData();renderTraceDetail(null);applyRoleGuards();if(!els.chatLog.children.length)appendMessage("assistant","控制台已就绪。现在可以上传知识文档、查看 Trace、创建自动化任务，也可以继续用主工作台和指定助手对话。","系统");await waitForUiPaint();hideAuthOverlay()}catch{state.currentUser=null;await refreshBootstrapStatus();showAuthOverlay(state.bootstrapRequired?"请先初始化管理员账号。":"请先登录控制台。")}},minDurationMs)}
els.loginForm.addEventListener("submit",async e=>{e.preventDefault();showAuthLoading("正在验证账号密码...");try{await withLoadingGate("正在验证账号密码...",async()=>{const p=await api("/api/auth/login",{method:"POST",body:JSON.stringify({username:els.loginUsername.value.trim(),password:els.loginPassword.value}),suppressAuthOverlay:true});state.currentUser=p.user;state.csrfToken=p.csrf_token||"";state.security=p.security||state.security;els.loginPassword.value="";showAuthLoading("正在登录并加载控制台...");await bootstrapSession("正在登录并加载控制台...",1200)},700)}catch(err){showAuthOverlay(err.message)}});
els.bootstrapForm?.addEventListener("submit",async e=>{e.preventDefault();showAuthLoading("正在初始化管理员账号...");try{await withLoadingGate("正在初始化管理员账号...",async()=>{const p=await api("/api/auth/bootstrap",{method:"POST",body:JSON.stringify({username:els.bootstrapUsername.value.trim(),password:els.bootstrapPassword.value}),suppressAuthOverlay:true});state.currentUser=p.user;state.csrfToken=p.csrf_token||"";state.bootstrapRequired=false;state.security=p.security||state.security;els.bootstrapPassword.value="";showAuthLoading("正在初始化账号并加载控制台...");await bootstrapSession("正在初始化账号并加载控制台...",1200)},700)}catch(err){els.bootstrapError.textContent=err.message;showAuthOverlay()}}); 
els.logoutBtn.addEventListener("click",async()=>{try{await api("/api/auth/logout",{method:"POST",suppressAuthOverlay:true})}finally{state.currentUser=null;state.csrfToken="";state.users=[];state.knowledgeDocuments=[];state.tasks=[];state.traces=[];renderUsers();renderKnowledgeDocuments();renderTasks();renderTraces();renderTraceDetail(null);await refreshBootstrapStatus();showAuthOverlay(state.bootstrapRequired?"请先初始化管理员账号。":"已退出登录。")}});
els.assistantList.addEventListener("click",e=>{const t=e.target.closest("[data-start-assistant]");if(t){state.startedAssistantId=t.dataset.startAssistant;renderAssistants();return}const card=e.target.closest("[data-assistant-id]");if(card)selectAssistant(card.dataset.assistantId)});
els.uploadList.addEventListener("click",e=>{const btn=e.target.closest("[data-remove-upload]");if(!btn)return;state.pendingUploads=state.pendingUploads.filter(i=>i.path!==btn.dataset.removeUpload);renderUploads()});
els.chatForm.addEventListener("submit",async e=>{e.preventDefault();if(state.isSending)return;const content=els.chatInput.value.trim(),current=[...state.pendingUploads];if(!content&&!current.length)return;state.isSending=true;appendMessage("user",[content,current.length?`上传文件：${current.map(i=>i.name).join("，")}`:""].filter(Boolean).join("\n")||"上传了文件","用户");els.chatInput.value="";state.pendingUploads=[];renderUploads();try{const result=await api("/api/chat",{method:"POST",body:JSON.stringify({assistant_id:state.selectedAssistantId,content,session_id:state.sessionId,channel:"web",chat_id:"web",uploaded_paths:current.map(i=>i.path),sync_enabled:can("admin")&&state.channelSyncEnabled&&!content.startsWith("/"),sync_channel:els.targetChannel.value.trim()})});if(result.assistant_id&&result.assistant_id!==state.selectedAssistantId)selectAssistant(result.assistant_id);if(result.changed_binding&&result.assistant_id){state.startedAssistantId=result.assistant_id;renderAssistants()}if(result.deferred){const map=new Map(state.deferredUploads.map(i=>[i.path,i]));for(const item of current)map.set(item.path,item);state.deferredUploads=Array.from(map.values());renderUploads();await loadOverview();await loadTraces();return}state.deferredUploads=[];renderUploads();const quotaText=result.quota?.daily_token_limit?`\n\n今日配额：${fmtNum(result.quota.daily_token_usage||0)} / ${fmtNum(result.quota.daily_token_limit||0)} tokens`:"";appendMessage("assistant",`${result.content||""}${quotaText}`.trim(),`${result.assistant_name||"助手"} · ${result.assistant_id||""}`,result.media||[],result.content_style||"chat",result.usage||null,result.citations||[]);if(result.channel_sync?.status==="sent"){const targetText=result.channel_sync.chat_id?`\n目标：${result.channel_sync.chat_id}`:"";const summary=result.channel_sync.media_count?`已同步发送到 ${chLabel(result.channel_sync.channel)} 绑定账号${targetText}\n图片 ${result.channel_sync.media_count} 张`:`已同步发送到 ${chLabel(result.channel_sync.channel)} 绑定账号${targetText}\n${result.channel_sync.content||"发送成功"}`;appendMessage("assistant",summary,"渠道发送")}else if(result.channel_sync?.status==="error")appendMessage("assistant",result.channel_sync.message||"渠道同步发送失败","渠道发送失败");await loadOverview();await loadTraces()}catch(err){appendMessage("assistant",err.message,"系统错误")}finally{state.isSending=false}});
form.root.addEventListener("submit",async e=>{e.preventDefault();try{const payload=assistantPayload(),exists=state.assistants.some(i=>i.id===payload.id),url=exists?`/api/assistants/${encodeURIComponent(payload.id)}`:"/api/assistants",method=exists?"PUT":"POST";const saved=await api(url,{method,body:JSON.stringify(payload)});await loadOverview();selectAssistant(saved.id)}catch(err){alert(err.message)}});
els.newAssistantBtn.addEventListener("click",()=>{state.selectedAssistantId=null;populateForm(null);els.assistantBadge.textContent="准备新增助手";renderAssistants();updateConfigPanel()});
els.deleteAssistantBtn.addEventListener("click",async()=>{if(!state.selectedAssistantId||!confirm(`确认删除助手 ${state.selectedAssistantId} 吗？`))return;try{await api(`/api/assistants/${encodeURIComponent(state.selectedAssistantId)}`,{method:"DELETE"});state.selectedAssistantId=null;await loadOverview()}catch(err){alert(err.message)}});
els.resetAssistantBtn.addEventListener("click",()=>populateForm(state.assistants.find(i=>i.id===state.selectedAssistantId)||null));
els.clearChatBtn.addEventListener("click",()=>{els.chatLog.innerHTML="";state.sessionId=`web:${crypto.randomUUID()}`;els.sessionId.textContent=state.sessionId;if(els.heroSessionId)els.heroSessionId.textContent=state.sessionId;state.pendingUploads=[];state.deferredUploads=[];renderUploads()});
els.channelSyncToggleBtn.addEventListener("click",()=>{state.channelSyncEnabled=!state.channelSyncEnabled;renderChannelSyncState()});
els.targetChannel.addEventListener("change",()=>{state.targetChannelSelection=els.targetChannel.value.trim()});
els.refreshBtn.addEventListener("click",async()=>{await loadOverview();await refreshPlatformData()});
els.toggleConfigBtn?.addEventListener("click",()=>{state.configExpanded=!state.configExpanded;updateConfigPanel()});
els.mcpFilesystemTemplateBtn.addEventListener("click",()=>setMcpTemplate(buildFilesystemMcpTemplate()));
els.mcpHttpTemplateBtn.addEventListener("click",()=>setMcpTemplate(buildHttpMcpTemplate()));
els.mcpValidateBtn.addEventListener("click",async()=>{try{await runMcpCheck("validate")}catch(err){state.mcpDiagnostics={servers:[{name:"MCP",valid:false,issues:[err.message],warnings:[]}]};renderMcpDiagnostics()}});
els.mcpProbeBtn.addEventListener("click",async()=>{try{await runMcpCheck("probe")}catch(err){state.mcpDiagnostics={servers:[{name:"MCP",valid:false,issues:[err.message],warnings:[]}]};renderMcpDiagnostics()}});
els.chatInput.addEventListener("keydown",e=>{if(e.key==="Enter"&&!e.shiftKey&&!e.isComposing&&!state.isComposing){e.preventDefault();els.chatForm.requestSubmit()}});
els.chatInput.addEventListener("compositionstart",()=>{state.isComposing=true});
els.chatInput.addEventListener("compositionend",()=>{state.isComposing=false});
els.fileInput.addEventListener("change",async e=>{try{await uploadFiles(Array.from(e.target.files||[]))}catch(err){appendMessage("assistant",err.message,"上传失败")}finally{els.fileInput.value=""}});
els.voiceBtn.addEventListener("click",()=>{if(!state.recognition)return;state.isRecognizing?state.recognition.stop():state.recognition.start()});
els.knowledgeUploadForm.addEventListener("submit",async e=>{e.preventDefault();const files=Array.from(els.knowledgeFiles.files||[]);if(!files.length){alert("请先选择至少一个知识库文件。");return}try{const data=new FormData();data.append("title",els.knowledgeTitle.value.trim());data.append("assistant_scope",els.knowledgeScope.value.trim());for(const file of files)data.append("files",file);await api("/api/knowledge/upload",{method:"POST",body:data});els.knowledgeFiles.value="";els.knowledgeTitle.value="";await loadOverview();await loadKnowledgeDocuments();await loadRagStatus()}catch(err){alert(err.message)}});
els.knowledgeSearchForm.addEventListener("submit",async e=>{e.preventDefault();const q=els.knowledgeQuery.value.trim();if(!q)return;try{await searchKnowledge(q)}catch(err){alert(err.message)}});
els.knowledgeList.addEventListener("click",async e=>{const openBtn=e.target.closest("[data-open-knowledge]"),delBtn=e.target.closest("[data-delete-knowledge]");if(openBtn){try{await loadKnowledgeDocumentDetail(openBtn.dataset.openKnowledge)}catch(err){alert(err.message)}return}if(!delBtn||!confirm("确认删除这份知识文档吗？"))return;try{if(state.selectedKnowledgeId===delBtn.dataset.deleteKnowledge){state.selectedKnowledgeId=null;state.selectedKnowledgeDetail=null;renderKnowledgeDetail()}await api(`/api/knowledge/documents/${encodeURIComponent(delBtn.dataset.deleteKnowledge)}`,{method:"DELETE"});await loadOverview();await loadKnowledgeDocuments();await loadRagStatus()}catch(err){alert(err.message)}});
els.taskForm.addEventListener("submit",async e=>{e.preventDefault();try{await api("/api/tasks",{method:"POST",body:JSON.stringify({id:els.taskId.value.trim()||null,name:els.taskName.value.trim(),assistant_id:els.taskAssistantId.value.trim()||state.selectedAssistantId||"consult",prompt:els.taskPrompt.value.trim(),task_kind:els.taskKind.value,collaboration_mode:els.taskCollaborationMode.value,schedule_kind:els.taskScheduleKind.value,cron_expression:els.taskCronExpression.value.trim(),interval_minutes:Number(els.taskIntervalMinutes.value||0),require_rag_connected:els.taskRequireRag.checked,require_channel_online:els.taskRequireChannel.checked,min_success_gap_minutes:Number(els.taskMinSuccessGap.value||0),max_retries:Number(els.taskMaxRetries.value||0),retry_backoff_seconds:Number(els.taskRetryBackoff.value||60),target_channel:els.taskTargetChannel.value.trim(),target_chat_id:els.taskTargetChatId.value.trim(),enabled:els.taskEnabled.checked})});resetTaskForm();await loadOverview();await loadTasks()}catch(err){alert(err.message)}});
els.taskResetBtn.addEventListener("click",()=>resetTaskForm());
els.taskList.addEventListener("click",async e=>{const edit=e.target.closest("[data-edit-task]"),run=e.target.closest("[data-run-task]"),runs=e.target.closest("[data-runs-task]"),del=e.target.closest("[data-delete-task]");if(edit){populateTaskForm(state.tasks.find(i=>i.id===edit.dataset.editTask)||null);return}if(run){try{const r=await api(`/api/tasks/${encodeURIComponent(run.dataset.runTask)}/run`,{method:"POST"});appendMessage("assistant",r.content||r.skip_reason||"任务执行完成",`任务中心 · ${r.assistant_id||""}`,r.media||[],r.content_style||"chat");await loadOverview();await loadTasks();await loadTraces()}catch(err){alert(err.message)}return}if(runs){try{await loadTaskRuns(runs.dataset.runsTask)}catch(err){alert(err.message)}return}if(del&&confirm("确认删除这个任务吗？"))try{await api(`/api/tasks/${encodeURIComponent(del.dataset.deleteTask)}`,{method:"DELETE"});state.selectedTaskId=null;state.taskRuns=[];await loadOverview();await loadTasks()}catch(err){alert(err.message)}});
els.traceList.addEventListener("click",async e=>{const btn=e.target.closest("[data-open-trace]");if(!btn)return;try{await loadTraceDetail(btn.dataset.openTrace)}catch(err){alert(err.message)}});
els.userForm.addEventListener("submit",async e=>{e.preventDefault();const role=els.userRole.value.trim()||"viewer";if(!["viewer","admin"].includes(role)){alert("角色必须选择 viewer 或 admin");return}if(!els.userUsername.value.trim()){alert("用户名不能为空");return}try{await api("/api/users",{method:"POST",body:JSON.stringify({id:els.userId.value.trim()||null,username:els.userUsername.value.trim(),password:els.userPassword.value||null,role,enabled:els.userEnabled.checked})});populateUserForm(null);await loadUsers()}catch(err){alert(err.message)}});
els.userResetBtn.addEventListener("click",()=>populateUserForm(null));
els.userList.addEventListener("click",async e=>{const edit=e.target.closest("[data-edit-user]"),del=e.target.closest("[data-delete-user]");if(edit){populateUserForm(state.users.find(i=>i.id===edit.dataset.editUser)||null);return}if(del&&confirm("确认删除这个账号吗？"))try{await api(`/api/users/${encodeURIComponent(del.dataset.deleteUser)}`,{method:"DELETE"});await loadUsers()}catch(err){alert(err.message)}});
document.querySelector(".sidebar-nav")?.addEventListener("click",e=>{const link=e.target.closest(".sidebar-link");if(link)activateNavLink(".sidebar-link",link)});
document.querySelector(".workspace-tabs")?.addEventListener("click",e=>{const link=e.target.closest(".workspace-tab");if(link)activateNavLink(".workspace-tab",link)});
window.addEventListener("resize",()=>{if(!state.configExpanded)syncConfigPanelHeight();refreshCardResizers()});
["change","input"].forEach(evt=>{els.taskScheduleKind.addEventListener(evt,renderTaskSchedulePreview);els.taskCollaborationMode.addEventListener(evt,renderTaskSchedulePreview);els.taskCronExpression.addEventListener(evt,renderTaskSchedulePreview);els.taskIntervalMinutes.addEventListener(evt,renderTaskSchedulePreview);els.taskRequireRag.addEventListener(evt,renderTaskSchedulePreview);els.taskRequireChannel.addEventListener(evt,renderTaskSchedulePreview);els.taskMinSuccessGap.addEventListener(evt,renderTaskSchedulePreview)});
window.addEventListener("load",async()=>{initSpeechRecognition();initCardResizers();updateConfigPanel();renderDeferredStatus();renderChannelSyncState();renderRagStatus();renderMcpDiagnostics();renderAssistantVersions();renderKnowledgeSearchResults();renderKnowledgeDocuments();renderKnowledgeDetail();renderTaskSchedulePreview();renderTasks();renderTraces();renderTraceDetail(null);renderUsers();if(typeof ResizeObserver!=="undefined"&&els.assistantsPanel){const ob=new ResizeObserver(()=>{if(!state.configExpanded)syncConfigPanelHeight();refreshCardResizers()});ob.observe(els.assistantsPanel)}await bootstrapSession()});
setInterval(()=>{if(!state.currentUser)return;loadOverview().catch(()=>{});loadTraces().catch(()=>{})},5000);
